import{_ as a,o as s,c as e,S as t}from"./chunks/framework.C6RQlTYc.js";const k=JSON.parse('{"title":"面试官问：Token 和分词是什么？为什么 Token 数量影响成本和性能？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_7-tokenization.md","filePath":"面试官问/17ai/q_ai_7-tokenization.md","lastUpdated":1778207238000}'),i={name:"面试官问/17ai/q_ai_7-tokenization.md"};function o(p,n,l,r,d,c){return s(),e("div",null,[...n[0]||(n[0]=[t(`<h1 id="面试官问-token-和分词是什么-为什么-token-数量影响成本和性能" tabindex="-1">面试官问：Token 和分词是什么？为什么 Token 数量影响成本和性能？ <a class="header-anchor" href="#面试官问-token-和分词是什么-为什么-token-数量影响成本和性能" aria-label="Permalink to &quot;面试官问：Token 和分词是什么？为什么 Token 数量影响成本和性能？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_8-tokenization.html">Token 与分词</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_21-context_window.html">上下文窗口</a></p></blockquote><p><strong>场景</strong>：面试官问&quot;你知道 GPT 的 Token 是什么吗？为什么我们调用 API 是按 Token 计费？&quot;</p><p><strong>考察点</strong>：Token 概念、分词算法、Token 数量对成本和性能的影响</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p><strong>Token</strong> 是大模型处理文本的最小单位，不完全等同于&quot;字&quot;或&quot;词&quot;。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;你好世界 AI&quot; </span></span>
<span class="line"><span>BPE 分词后 → [&quot;你&quot;, &quot;好&quot;, &quot;世界&quot;, &quot; AI&quot;]  ← 4 tokens</span></span>
<span class="line"><span>不一定是一字一 token，英文常见 1 word ≈ 1.3 tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中文每字约 1.5-2 tokens（视模型而定）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>分词方法</strong>：</p><table><thead><tr><th>方法</th><th>原理</th><th>代表</th></tr></thead><tbody><tr><td>BPE</td><td>统计高频子词合并</td><td>GPT 系列</td></tr><tr><td>WordPiece</td><td>似然概率选择合并</td><td>BERT</td></tr><tr><td>SentencePiece</td><td>语言无关，直接处理原始文本</td><td>LLaMA、T5</td></tr></tbody></table><p><strong>Token 为什么影响成本和性能</strong>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>成本公式：总费用 = (输入 tokens × 输入单价) + (输出 tokens × 输出单价)</span></span>
<span class="line"><span>例如 GPT-4：输入 $0.03/1K token，输出 $0.06/1K token</span></span>
<span class="line"><span>一次 2000 token 的对话 ≈ $0.03~$0.10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>性能影响：</span></span>
<span class="line"><span>├── 上下文窗口 = 最大 token 数量限制（如 4K/8K/128K）</span></span>
<span class="line"><span>├── 超过窗口的内容会被截断或遗忘</span></span>
<span class="line"><span>└── 理论上，Transformer 自注意力的计算复杂度是 O(n²)</span></span>
<span class="line"><span>    —— 输入翻倍，计算量大约翻 4 倍</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>前端实用技巧</strong>：</p><ul><li>用 <code>tiktoken</code> 或 API 返回的 <code>usage.total_tokens</code> 统计用量</li><li>长文本先摘要再送入模型（节省 token）</li><li>视觉 LLM 中图片也计 token（约 85~170 token/图块）</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>理解 Token 是大模型的最小处理单元，不是&quot;字&quot;</li><li>说明 token 数量的两个影响：成本 + 上下文窗口限制</li><li>知道 BPE 是最主流的分词算法</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_8-tokenization.html">Token 与分词概念讲解</a></p></blockquote>`,6)])])}const b=a(i,[["render",o]]);export{k as __pageData,b as default};
